def route(record: dict) -> str:
    required = {'case_id', 'tasks', 'slices', 'rubric_levels', 'holdout'}
    absent = sorted(k for k in required if k not in record)
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = not (sum(record["slices"].values()) != record["tasks"] or record["holdout"] == 0)
    return "PASS" if ok else "REBUILD_EVAL_DATASET"

valid = {'case_id': 'CASO-ICA-050-1A', 'tasks': 40, 'slices': {'adversarial': 5, 'edge': 10, 'normal': 25}, 'rubric_levels': {0, 1, 2, 3}, 'holdout': 10}
